output.sparql:
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?winner ?name WHERE {
  ?award wdt:P31 /(wdt:P279 *) wd:Q16191288 .
  ?winner wdt:P166 ?award .
  {
    ?winner wdt:P69 wd:Q1057890
  } UNION {
    ?winner wdt:P108 wd:Q1057890
  }
  .
  ?winner rdfs:label ?name .
  FILTER(LANG(?name) = "en")
}
